class Solution {
public:
    int distanceTraveled(int mainTank, int additionalTank) {
        int distance = 0;
        while (mainTank > 0) {
            if (mainTank >= 5 && additionalTank >= 1) {
                mainTank -= 5;
                additionalTank -= 1;
                mainTank += 1;
                distance += 50;
            } else {
                int fuelToBurn = min(mainTank, mainTank);
                distance += fuelToBurn * 10;
                mainTank -= fuelToBurn;
            }
        }
        return distance;
    }
};
```
